// Overlays real @carbon/vue re-export wrappers on top of the web-components-wrapper
// vue/components/*.vue files generated by generate.mjs, wherever a real CvXxx component
// exists (scripts/vue-manifest.json, built by extract-vue-manifest.mjs from the actual
// carbon-components-vue GitHub source). @carbon/vue is Carbon 10 (carbon-components,
// "bx--" prefix) — one major version behind the Carbon 11 design everywhere else in this
// project — so this is flagged in both the file comment and the index page.
import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';

const vueManifest = JSON.parse(readFileSync('scripts/vue-manifest.json', 'utf8'));

mkdirSync('vue/components', { recursive: true });

const written = [];
for (const { cvName, folder } of vueManifest) {
  const compName = cvName.replace(/^Cv/, '');
  const content = `<!--
  Vue wrapper for the REAL, official @carbon/vue component <${cvName}>.

  Note: @carbon/vue targets Carbon 10 (the "carbon-components" package, "bx--" class
  prefix) — one major version behind the Carbon 11 design (@carbon/react, @carbon/styles,
  @carbon/web-components) used everywhere else in this project. It is genuinely IBM's
  official Vue package, but it will render with older colors/spacing/typography.

  Install:
    npm install --save @carbon/vue vue

  Global setup (main.js):
    import CarbonVue3 from '@carbon/vue';
    import '@carbon/vue/dist/carbon-vue-3.css';
    app.use(CarbonVue3);

  Usage:
    import ${compName} from './components/${compName}.vue';
    <${compName}>...</${compName}>
-->
<script>
import { ${cvName} } from '@carbon/vue';
export default ${cvName};
</script>
`;
  writeFileSync(`vue/components/${compName}.vue`, content);
  written.push({ compName, cvName, folder });
}

writeFileSync('scripts/vue-override-written.json', JSON.stringify(written, null, 2));
console.log(`wrote ${written.length} real @carbon/vue wrapper files`);
